'use client';

import React, { useState } from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { MediaBrowser } from './MediaBrowser';

interface PartnerShowcaseHeroPropertyPanelProps {
  section: SectionConfig;
  onUpdate: (updates: Partial<SectionConfig>) => void;
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{label}</label>
      {children}
    </div>
  );
}

const inputCls = 'w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm';
const textareaCls = inputCls + ' resize-none';

function Collapsible({ title, badge, children, defaultOpen = false }: {
  title: string; badge?: string; children: React.ReactNode; defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="border border-gray-200 dark:border-gray-600 rounded-lg overflow-hidden">
      <button
        type="button"
        onClick={() => setOpen(o => !o)}
        className="w-full flex items-center justify-between px-3 py-2.5 bg-gray-50 dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors text-left"
      >
        <span className="text-sm font-medium text-gray-800 dark:text-white flex items-center gap-2">
          {title}
          {badge && <span className="text-xs bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-2 py-0.5 rounded-full">{badge}</span>}
        </span>
        <span className={`text-gray-400 text-xs transition-transform ${open ? 'rotate-90' : ''}`}>▶</span>
      </button>
      {open && <div className="p-3 space-y-3 bg-white dark:bg-gray-800">{children}</div>}
    </div>
  );
}

function ImageField({ label, value, onChange }: { label: string; value: string; onChange: (url: string) => void }) {
  const [showBrowser, setShowBrowser] = useState(false);
  const [uploading, setUploading] = useState(false);

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    try {
      const formData = new FormData();
      formData.append('file', file);
      const token = localStorage.getItem('adminToken');
      const res = await fetch('/api/admin/media', {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      });
      if (res.ok) {
        const data = await res.json();
        onChange(data.url);
      }
    } finally {
      setUploading(false);
    }
  };

  return (
    <Field label={label}>
      {value && (
        <div className="relative w-full h-24 rounded-lg overflow-hidden border border-gray-300 dark:border-gray-600 mb-2">
          <img src={value} alt="preview" className="w-full h-full object-cover" />
          <button onClick={() => onChange('')} className="absolute top-1 right-1 p-1 bg-red-600 text-white rounded-full text-xs">✕</button>
        </div>
      )}
      <div className="flex gap-2">
        <input type="text" value={value} onChange={e => onChange(e.target.value)} placeholder="Image URL" className={`flex-1 ${inputCls}`} />
        <button type="button" onClick={() => setShowBrowser(true)} className="px-3 py-2 bg-purple-600 text-white rounded-md hover:bg-purple-700 text-sm">📚</button>
        <label className="px-3 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 cursor-pointer text-sm">
          {uploading ? '⏳' : '📤'}
          <input type="file" accept="image/*,video/*" onChange={handleUpload} className="hidden" disabled={uploading} />
        </label>
      </div>
      <MediaBrowser isOpen={showBrowser} onClose={() => setShowBrowser(false)} onSelect={url => { onChange(url); setShowBrowser(false); }} acceptTypes={['image/*', 'video/*']} />
    </Field>
  );
}

export function PartnerShowcaseHeroPropertyPanel({ section, onUpdate }: PartnerShowcaseHeroPropertyPanelProps) {
  const data = section.data as any;
  const update = (patch: Record<string, any>) => onUpdate({ data: { ...data, ...patch } });

  const buttons = data.buttons ?? [];
  const trustItems = data.trustItems ?? [];

  const updateButton = (idx: number, field: string, val: string) => {
    const next = buttons.map((b: any, i: number) => i === idx ? { ...b, [field]: val } : b);
    update({ buttons: next });
  };

  const updateTrust = (idx: number, field: string, val: string) => {
    const next = trustItems.map((t: any, i: number) => i === idx ? { ...t, [field]: val } : t);
    update({ trustItems: next });
  };

  return (
    <div className="space-y-4">

      <Collapsible title="Hero Content" defaultOpen>
        <Field label="Label Text">
          <input className={inputCls} value={data.label ?? ''} onChange={e => update({ label: e.target.value })} />
        </Field>
        <Field label="Label Highlight">
          <input className={inputCls} value={data.labelHighlight ?? ''} onChange={e => update({ labelHighlight: e.target.value })} />
        </Field>
        <Field label="Title (first line)">
          <input className={inputCls} value={data.title ?? ''} onChange={e => update({ title: e.target.value })} />
        </Field>
        <Field label="Title Middle (second line)">
          <input className={inputCls} value={data.titleMiddle ?? ''} onChange={e => update({ titleMiddle: e.target.value })} placeholder="e.g. will rely on —" />
        </Field>
        <Field label="Title Highlight (gradient)">
          <input className={inputCls} value={data.titleHighlight ?? ''} onChange={e => update({ titleHighlight: e.target.value })} />
        </Field>
        <Field label="Description">
          <textarea className={textareaCls} rows={3} value={data.description ?? ''} onChange={e => update({ description: e.target.value })} />
        </Field>
      </Collapsible>

      <Collapsible title="CTA Buttons" badge={`${buttons.length}`}>
        {buttons.map((btn: any, i: number) => (
          <div key={i} className="p-2 border border-gray-200 dark:border-gray-600 rounded-lg space-y-2">
            <div className="flex items-center justify-between mb-1">
              <span className="text-xs font-medium text-gray-600 dark:text-gray-400">Button {i + 1}</span>
              <button type="button" onClick={() => update({ buttons: buttons.filter((_: any, bi: number) => bi !== i) })} className="text-xs text-red-500 hover:text-red-700">✕ Remove</button>
            </div>
            <Field label="Text">
              <input className={inputCls} value={btn.text} onChange={e => updateButton(i, 'text', e.target.value)} />
            </Field>
            <Field label="Link (href)">
              <input className={inputCls} value={btn.href} onChange={e => updateButton(i, 'href', e.target.value)} />
            </Field>
            <Field label="Variant">
              <select className={inputCls} value={btn.variant} onChange={e => updateButton(i, 'variant', e.target.value)}>
                <option value="primary">Primary (gradient)</option>
                <option value="secondary">Secondary (outline)</option>
              </select>
            </Field>
          </div>
        ))}
        <button type="button" onClick={() => update({ buttons: [...buttons, { text: 'New Button', href: '#', variant: 'secondary' }] })}
          className="w-full py-2 border border-dashed border-gray-300 dark:border-gray-600 rounded-md text-sm text-gray-500 hover:border-blue-400 hover:text-blue-500 transition-colors">
          + Add Button
        </button>
      </Collapsible>

      <Collapsible title="Trust Strip Stats" badge={`${trustItems.length}`}>
        {trustItems.map((item: any, i: number) => (
          <div key={i} className="flex gap-2 items-start">
            <div className="flex-1 space-y-1">
              <input className={inputCls} placeholder="Value (e.g. 5–8×)" value={item.value} onChange={e => updateTrust(i, 'value', e.target.value)} />
              <input className={inputCls} placeholder="Label" value={item.label} onChange={e => updateTrust(i, 'label', e.target.value)} />
            </div>
            <button type="button" onClick={() => update({ trustItems: trustItems.filter((_: any, ti: number) => ti !== i) })}
              className="mt-1 p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded">✕</button>
          </div>
        ))}
        <button type="button" onClick={() => update({ trustItems: [...trustItems, { value: '', label: '' }] })}
          className="w-full py-2 border border-dashed border-gray-300 dark:border-gray-600 rounded-md text-sm text-gray-500 hover:border-blue-400 hover:text-blue-500 transition-colors">
          + Add Stat
        </button>
      </Collapsible>

      <Collapsible title="Background Colors">
        <div className="grid grid-cols-2 gap-2">
          <Field label="Dark Mode BG">
            <div className="flex gap-1 items-center">
              <input type="color" value={data.darkBg ?? '#0f172a'} onChange={e => update({ darkBg: e.target.value })}
                className="w-9 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700" />
              <input className={inputCls} value={data.darkBg ?? ''} onChange={e => update({ darkBg: e.target.value })} placeholder="rgb(15 23 42)" />
            </div>
          </Field>
          <Field label="Light Mode BG">
            <div className="flex gap-1 items-center">
              <input type="color" value={data.lightBg ?? '#ffffff'} onChange={e => update({ lightBg: e.target.value })}
                className="w-9 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700" />
              <input className={inputCls} value={data.lightBg ?? ''} onChange={e => update({ lightBg: e.target.value })} placeholder="#ffffff" />
            </div>
          </Field>
        </div>
      </Collapsible>

      <Collapsible title="Accent Colors">
        <div className="grid grid-cols-3 gap-2">
          {(['accentColor', 'accentColor2', 'accentColor3'] as const).map((key, i) => (
            <Field key={key} label={['Primary', 'Secondary', 'Tertiary'][i]}>
              <div className="flex gap-1 items-center">
                <input type="color" value={data[key] ?? '#4F7FFF'} onChange={e => update({ [key]: e.target.value })}
                  className="w-9 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700" />
                <input className={inputCls} value={data[key] ?? '#4F7FFF'} onChange={e => update({ [key]: e.target.value })} />
              </div>
            </Field>
          ))}
        </div>
      </Collapsible>

    </div>
  );
}
